      codeExamples: [
        {
          title: 'Subsets - Include/Exclude Pattern',
          description: 'Generate all 2^n subsets of an array.',
          code: `def subsets(nums):
    result = []

    def backtrack(start, path):
        result.append(path[:])  # Add current subset

        for i in range(start, len(nums)):
            path.append(nums[i])      # Choose
            backtrack(i + 1, path)     # Explore
            path.pop()                 # Unchoose (backtrack)

    backtrack(0, [])
    return result`
        },
        {
          title: 'Permutations - Use Each Once',
          description: 'Generate all n! permutations.',
          code: `def permute(nums):
    result = []

    def backtrack(path, used):
        if len(path) == len(nums):
            result.append(path[:])
            return

        for i in range(len(nums)):
            if used[i]:
                continue
            used[i] = True          # Choose
            path.append(nums[i])
            backtrack(path, used)   # Explore
            path.pop()              # Unchoose
            used[i] = False

    backtrack([], [False] * len(nums))
    return result`
        },
        {
          title: 'Combination Sum - Reuse Allowed',
          description: 'Find combinations that sum to target, can reuse elements.',
          code: `def combination_sum(candidates, target):
    result = []

    def backtrack(start, path, remaining):
        if remaining == 0:
            result.append(path[:])
            return
        if remaining < 0:
            return  # Prune

        for i in range(start, len(candidates)):
            path.append(candidates[i])
            # Can reuse same element, so pass i not i+1
            backtrack(i, path, remaining - candidates[i])
            path.pop()

    backtrack(0, [], target)
    return result`
        },
        {
          title: 'N-Queens - Constraint Satisfaction',
          description: 'Place N queens on N×N board with no attacks.',
          code: `def solve_n_queens(n):
    result = []
    board = [['.'] * n for _ in range(n)]

    def is_safe(row, col):
        # Check column
        for i in range(row):
            if board[i][col] == 'Q':
                return False
        # Check diagonals
        for i, j in zip(range(row-1, -1, -1), range(col-1, -1, -1)):
            if board[i][j] == 'Q':
                return False
        for i, j in zip(range(row-1, -1, -1), range(col+1, n)):
            if board[i][j] == 'Q':
                return False
        return True

    def backtrack(row):
        if row == n:
            result.append([''.join(r) for r in board])
            return

        for col in range(n):
            if is_safe(row, col):
                board[row][col] = 'Q'  # Choose
                backtrack(row + 1)      # Explore
                board[row][col] = '.'  # Unchoose

    backtrack(0)
    return result`
        }
      ],
